import { mat2d, vec2 } from 'gl-matrix';
import { useImageViewerContext } from './ImageViewerContext';
import { usePointerHandler } from './usePointerHandler';
import { VEC2_SCALE_OF_ORIGINAL_SIZE } from './constants';

export const useImageViewerMobileScaling = () => {
  const { setMatrixByPoints, getScale, minScale, maxScale } = useImageViewerContext();
  /**
   * Scaling
   * - 触屏设备 pinch（双点，onPointerDown + Move + Up）
   */
  const doubleTouchScalingHandler = usePointerHandler({
    move: (ev, pointerIds) => {
      const lastEvent = pointerIds.get(ev.pointerId);
      if (pointerIds.size === 2 && lastEvent) {
        // 双点触控
        const _pointerIds = new Map(pointerIds);
        const keys = [..._pointerIds.keys()];
        const currentScale = getScale();

        const getPoints = (ids: number[]) =>
          ids.map(k => {
            const _ev = _pointerIds.get(k)!;
            return vec2.fromValues(_ev.clientX, _ev.clientY);
          });

        let [p1, p2] = getPoints(keys);
        const originOld = vec2.scale(vec2.create(), vec2.add(vec2.create(), p1, p2), VEC2_SCALE_OF_ORIGINAL_SIZE);
        const vecOld = vec2.subtract(vec2.create(), p1, p2);

        _pointerIds.set(ev.pointerId, ev);
        [p1, p2] = getPoints(keys);

        const originNew = vec2.scale(vec2.create(), vec2.add(vec2.create(), p1, p2), VEC2_SCALE_OF_ORIGINAL_SIZE);
        const vecNew = vec2.subtract(vec2.create(), p1, p2);

        setMatrixByPoints(absolutePoint => {
          const point = vec2.subtract(vec2.create(), absolutePoint, originOld);
          const scale = Math.max(
            minScale / currentScale,
            Math.min(vec2.length(vecNew) / vec2.length(vecOld), maxScale / currentScale),
          ); // Limit the scale
          const scaling = mat2d.fromScaling(mat2d.create(), [scale, scale]);
          const translation = mat2d.fromTranslation(mat2d.create(), vec2.subtract(vec2.create(), originNew, originOld));
          return vec2.add(
            vec2.create(),
            vec2.transformMat2d(vec2.create(), point, mat2d.multiply(mat2d.create(), scaling, translation)),
            originOld,
          );
        });
      }
    },
  });

  return doubleTouchScalingHandler;
};
